SELECT user_name, email
FROM users
WHERE user_id NOT IN (
    SELECT created_by
    FROM models
)
AND user_id NOT IN (
    SELECT user_id
    FROM evaluation_sessions
);

SELECT u.user_name
FROM users u
JOIN evaluation_sessions es ON u.user_id = es.user_id
WHERE es.session_id = (
  SELECT MAX(session_id) FROM evaluation_sessions
);

SELECT m.model_name, mv.version_number, mv.release_date
FROM models AS m
JOIN model_versions AS mv ON m.model_id = mv.model_id;

SELECT COUNT(user_id) AS users_without_feedback
FROM users
WHERE user_id NOT IN (SELECT user_id FROM feedback);
